import{_ as a,c as s,a as i,o as t}from"./app-CEcM0piI.js";const n={};function d(r,e){return t(),s("div",null,e[0]||(e[0]=[i(`<h3 id="垂直居中" tabindex="-1"><a class="header-anchor" href="#垂直居中"><span>垂直居中</span></a></h3><p>css中并没有提供垂直居中的方法,可以使用line-height和height等高进行实现</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>a {</span></span>
<span class="line"><span>    display: block;</span></span>
<span class="line"><span>    width: 230px;</span></span>
<span class="line"><span>    height: 40px;</span></span>
<span class="line"><span>    background-color: rgb(80, 80, 80);</span></span>
<span class="line"><span>    line-height: 40px;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>行高的上空隙和下空隙把文字挤到中间了.是如果行高小于盒子高度，文字会偏上，如果行高大于盒子高度，则文字偏下</p><h3 id="背景图片" tabindex="-1"><a class="header-anchor" href="#背景图片"><span>背景图片</span></a></h3><ul><li>none : 无背景图(默认)</li><li>path : 要插入的背景图片地址</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>background-image:url(path)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>示例</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>background-image:url(&quot;image/logo.png&quot;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="背景平铺" tabindex="-1"><a class="header-anchor" href="#背景平铺"><span>背景平铺</span></a></h4><p>如果给出的背景图片与包含它的盒子的区域大小不同就会出现不同的现象 若盒子区域大,背景图片小就会重复多次显示背景图片占满区域 图片大,区域小就会裁剪</p><p>默认是平铺的,可以使用<code>background-repeat</code>属性进行设置</p><table><thead><tr><th>参数值</th><th>作用</th></tr></thead><tbody><tr><td>repeat</td><td>背景图像在纵向和横向上平铺(默认的）</td></tr><tr><td>no-repeat</td><td>背景图像不平铺</td></tr><tr><td>repeat-x</td><td>背景图像在横向上平铺</td></tr><tr><td>repeat-y</td><td>背景图像在纵向平铺<br></td></tr></tbody></table><h4 id="背景图片位置" tabindex="-1"><a class="header-anchor" href="#背景图片位置"><span>背景图片位置</span></a></h4><p>利用<code>background-position: x y</code>属性可以改变图片在背景中的位置。 需要指定两个参数分别对应x和y轴值</p><table><thead><tr><th>参数值</th><th>说明</th></tr></thead><tbody><tr><td>length</td><td>百分数|由浮点数字和单位标识符组成的长度值</td></tr><tr><td>position</td><td>top丨center丨bottom丨left丨center | right方位名词</td></tr></tbody></table><h4 id="背景图像固定" tabindex="-1"><a class="header-anchor" href="#背景图像固定"><span>背景图像固定</span></a></h4><p><code>background-attachment</code>属性设置背景图像是否固定或者随着页面的其余部分滚动。</p><table><thead><tr><th>参数</th><th>作用</th></tr></thead><tbody><tr><td>scroll</td><td>背景图像是随对象内容滚动</td></tr><tr><td>fixed</td><td>背景图像固定</td></tr></tbody></table><h4 id="背景复合写法" tabindex="-1"><a class="header-anchor" href="#背景复合写法"><span>背景复合写法</span></a></h4><p>当使用简写属性时，没有特定的书写顺序，一般习惯约定顺序为：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>background：背景颜色 背景图片 地址背景 平铺背景 图像滚动 背景图片位置</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="背景色半透明" tabindex="-1"><a class="header-anchor" href="#背景色半透明"><span>背景色半透明</span></a></h4><p>CSS3新增属性，是IE9+版本浏览器才支持的</p><p>最后一个参数是alpha透明度，取值范围在0~1之间</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>background: rgba(0，0，0，0.3);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>背景半透明是指盒子背景半透明，盒子里面的内容不受影响 小数点前面的0可以省略可以直接写.3</p>`,27)]))}const h=a(n,[["render",d]]),p=JSON.parse('{"path":"/front/css/3/","title":"3 显示方式实现","lang":"zh-CN","frontmatter":{"title":"3 显示方式实现","createTime":"2025/06/18 21:05:50","permalink":"/front/css/3/"},"readingTime":{"minutes":1.94,"words":582},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/3 显示方式实现.md","headers":[]}');export{h as comp,p as data};
